from pydantic import BaseModel, Field
from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)


class AtomicClaim(BaseModel):
    claim: str
    supported: bool = Field(description="True only if context explicitly states or implies this")
    quote: str = Field(description="The exact context phrase that supports it, or 'none'")


class ClaimVerification(BaseModel):
    claims: list[AtomicClaim]

    @property
    def faithfulness(self) -> float:
        if not self.claims:
            return 1.0
        return sum(c.supported for c in self.claims) / len(self.claims)

    @property
    def unsupported(self) -> list[str]:
        return [c.claim for c in self.claims if not c.supported]


verify_prompt = ChatPromptTemplate.from_messages([
    ("system", (
        "Decompose the answer into atomic claims (one fact per claim). "
        "For each claim, check if the context explicitly states or clearly implies it. "
        "Do NOT infer beyond what the context says."
    )),
    ("human", "Context:\n{context}\n\nAnswer:\n{answer}"),
])

verifier = verify_prompt | llm.with_structured_output(ClaimVerification)


def measure_faithfulness(answer: str, context: str) -> ClaimVerification:
    return verifier.invoke({"answer": answer, "context": context})


# Example
result = measure_faithfulness(
    answer="The return window is 30 days. You get free return shipping on all orders.",
    context="Electronics: 30-day return window. Original packaging required.",
)
print(f"Faithfulness: {result.faithfulness:.2f}")
for claim in result.claims:
    status = "✓" if claim.supported else "✗ HALLUCINATION"
    print(f"  {status}: {claim.claim}")
# ✓: The return window is 30 days.
# ✗ HALLUCINATION: You get free return shipping on all orders.

from dataclasses import dataclass
from typing import Literal


@dataclass
class AnswerDiagnosis:
    faithfulness: float
    answer_relevance: float
    quadrant: Literal["ideal", "on_topic_hallucination", "faithful_off_topic", "both_failing"]
    root_cause: str
    remediation: str


def diagnose_answer(faithfulness: float, answer_relevance: float) -> AnswerDiagnosis:
    HIGH_F = faithfulness >= 0.85
    HIGH_R = answer_relevance >= 0.80

    if HIGH_F and HIGH_R:
        return AnswerDiagnosis(
            faithfulness, answer_relevance, "ideal",
            "No issue detected",
            "Monitor for drift",
        )
    elif not HIGH_F and HIGH_R:
        return AnswerDiagnosis(
            faithfulness, answer_relevance, "on_topic_hallucination",
            "Model adds claims not in retrieved context despite addressing the question",
            "Add 'answer ONLY using the provided context' to system prompt; lower temperature to 0",
        )
    elif HIGH_F and not HIGH_R:
        return AnswerDiagnosis(
            faithfulness, answer_relevance, "faithful_off_topic",
            "Retriever returned irrelevant documents; model faithfully answered the wrong question",
            "Improve query rewriting, increase top_k, or add a relevance grader (CRAG pattern)",
        )
    else:
        return AnswerDiagnosis(
            faithfulness, answer_relevance, "both_failing",
            "Retrieval missed target documents AND model hallucinated",
            "Diagnose retriever first (check recall@k), then re-evaluate faithfulness with correct context",
        )


diag = diagnose_answer(faithfulness=0.5, answer_relevance=0.91)
print(f"Quadrant: {diag.quadrant}")
print(f"Root cause: {diag.root_cause}")
print(f"Fix: {diag.remediation}")
# Quadrant: on_topic_hallucination
# Root cause: Model adds claims not in context...
# Fix: Add 'answer ONLY using the provided context' to system prompt...

from dataclasses import dataclass, field
from collections import deque
import statistics

@dataclass
class QualityMonitor:
    faithfulness_threshold: float = 0.85
    relevance_threshold: float = 0.80
    window_size: int = 100  # Rolling window of recent queries
    _faithfulness_window: deque = field(default_factory=lambda: deque(maxlen=100))
    _relevance_window: deque = field(default_factory=lambda: deque(maxlen=100))

    def record(self, faithfulness: float, answer_relevance: float):
        self._faithfulness_window.append(faithfulness)
        self._relevance_window.append(answer_relevance)

    @property
    def rolling_faithfulness(self) -> float:
        return statistics.mean(self._faithfulness_window) if self._faithfulness_window else 0.0

    @property
    def rolling_relevance(self) -> float:
        return statistics.mean(self._relevance_window) if self._relevance_window else 0.0

    def check_alerts(self) -> list[str]:
        alerts = []
        if self.rolling_faithfulness < self.faithfulness_threshold:
            alerts.append(
                f"ALERT: faithfulness {self.rolling_faithfulness:.3f} < {self.faithfulness_threshold} "
                f"(last {len(self._faithfulness_window)} queries)"
            )
        if self.rolling_relevance < self.relevance_threshold:
            alerts.append(
                f"ALERT: answer_relevance {self.rolling_relevance:.3f} < {self.relevance_threshold}"
            )
        return alerts


monitor = QualityMonitor(faithfulness_threshold=0.85, relevance_threshold=0.80)

# Simulate recording evaluations from sampled production queries
for f, r in [(0.9, 0.85), (0.7, 0.88), (0.6, 0.91), (0.5, 0.89)]:
    monitor.record(f, r)

for alert in monitor.check_alerts():
    print(alert)
# ALERT: faithfulness 0.675 < 0.85 (last 4 queries)
